mapper.sql:
select APP_ID as appId,FLOW_ID as flowId,BIZ_ID as bizId,BIZ_NAME as name,PROJECT_NAME as projectName, to_char(START_TIME,'yyyy-MM-dd HH24:mi:ss') as startTime,to_char(FINISH_TIME,'yyyy-MM-dd HH24:mi:ss') as finishTime,STATUS, CASE WHEN CPU_CONSUMPTION = '0' THEN '0' WHEN to_char(CPU_CONSUMPTION,'fm999999999990.00') = '0.00' THEN '0' ELSE to_char(CPU_CONSUMPTION,'fm999999999990.00') END AS cpuConsumption, CASE WHEN MEMORY_CONSUMPTION = '0' THEN '0' WHEN to_char(MEMORY_CONSUMPTION,'fm999999999990.00') = '0.00' THEN '0' ELSE to_char(MEMORY_CONSUMPTION,'fm999999999990.00') END AS memoryConsumption, RUNNING_TIME as runningTime, TASK_IDS as taskIds,NODE_IDS as nodeIds,to_char(BIZ_DATE,'yyyy-MM-dd HH24:mi:ss') as bizDate from M_BUSINESS_INSTANCE
1=1
and BIZ_NAME like '%${queryParams.nodeNameInput}%'
and BIZ_DATE >= to_date(#{queryParams.bizDateBegin,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and BIZ_DATE <= to_date(#{queryParams.bizDateEnd,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and START_TIME >= to_date(#{queryParams.taskOpenDateBegin,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and START_TIME <= to_date(#{queryParams.taskOpenDateEnd,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and FINISH_TIME >= to_date(#{queryParams.taskEndDateBegin,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and FINISH_TIME <= to_date(#{queryParams.taskEndDateEnd,jdbcType=VARCHAR},'yyyy-mm-dd HH24:mi:ss')
and RUNNING_TIME >= #{queryParams.runningTimeBegin,jdbcType=VARCHAR}
and RUNNING_TIME <= #{queryParams.runningTimeEnd,jdbcType=VARCHAR}
and to_number(MEMORY_CONSUMPTION) >= #{queryParams.memoryConsumptionBegin,jdbcType=VARCHAR}
and to_number(MEMORY_CONSUMPTION) <= #{queryParams.memoryConsumptionEnd,jdbcType=VARCHAR}
and to_number(CPU_CONSUMPTION) >= #{queryParams.cpuConsumptionBegin,jdbcType=VARCHAR}
and to_number(CPU_CONSUMPTION) <= #{queryParams.cpuConsumptionEnd,jdbcType=VARCHAR}

